use cardano/assets
use cardano/transaction

pub type Datum {
  oracle_ref: transaction.OutputReference,
}

validator price_check {
  spend(datum: Option<Datum>, _redeemer, _own_ref, self) {
    expect Some(Datum { oracle_ref }) = datum
    expect Some(oracle_input) =
      transaction.find_input(self.reference_inputs, oracle_ref)
    expect Some(raw_datum) =
      transaction.find_datum(self.datums, oracle_input.output.datum)
    expect min_lovelace: Int = raw_datum
    let total_out =
      list.foldl(
        self.outputs,
        0,
        fn(o, acc) { acc + assets.lovelace_of(o.value) },
      )
    total_out >= min_lovelace
  }
}

use aiken/interval

pub type Datum {
  expiry: Int,
}

validator spend_before_expiry {
  spend(datum: Option<Datum>, _redeemer, _own_ref, self) {
    expect Some(Datum { expiry }) = datum
    interval.is_entirely_before(self.validity_range, expiry)
  }
}

use cardano/transaction

validator datum_from_reference {
  spend(_datum, _redeemer, _own_ref, self) {
    expect Some(ref_input) =
      list.head(self.reference_inputs)
    expect transaction.DatumHash(dh) = ref_input.output.datum
    expect Some(_config_data) = transaction.find_datum(self.datums, dh)
    True
  }
}

use cardano/transaction

pub type Datum {
  counter: Int,
}

validator increment_counter {
  spend(datum: Option<Datum>, _redeemer, own_ref, self) {
    expect Some(Datum { counter }) = datum
    let continuing = transaction.find_script_outputs(self.outputs, own_ref)
    expect Some(cont_output) = list.head(continuing)
    expect Some(raw) = transaction.find_datum(self.datums, cont_output.datum)
    expect Datum { counter: new_counter } = raw
    new_counter == counter + 1
  }
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/transaction

pub type Datum {
  config_ref: transaction.OutputReference,
}

validator ref_input_signer {
  spend(datum: Option<Datum>, _redeemer, _own_ref, self) {
    expect Some(Datum { config_ref }) = datum
    expect Some(ref_input) =
      transaction.find_input(self.reference_inputs, config_ref)
    expect Some(raw) =
      transaction.find_datum(self.datums, ref_input.output.datum)
    expect allowed_key: VerificationKeyHash = raw
    list.has(self.extra_signatories, allowed_key)
  }
}

use cardano/assets

validator capped_mint {
  mint(_redeemer, policy_id, self) {
    let policy_tokens = assets.tokens(self.mint, policy_id)
    let total =
      dict.foldl(policy_tokens, 0, fn(_name, qty, acc) { acc + qty })
    total <= 1000
  }
}

